def test_validates_accepts_multiple_fields(self):
    class BadSchema(Schema):
        foo = fields.String()
        bar = fields.String(data_key="Bar")

        @validates("foo", "bar")
        def validate_string(self, data: str, data_key: str):
            raise ValidationError(f"'{data}' is invalid for {data_key}.")

    schema = BadSchema()
