def test_method_validator(self):
    class MethodSerializer(Schema):
        name = fields.Method(
            "get_name", deserialize="get_name", validate=validate.Length(equal=3)
        )

        def get_name(self, val):
            return val.upper()

    assert MethodSerializer().load({"name": "joe"})
